use std::collections::HashMap;

#[derive(Debug)]
enum Status {
    Ok,
    BufferFull(u32),
    FifoOverflow(bool),
    UnknownError(i32),
}

struct PacketContext {
    status: Status,
    source_register_value: u32,
}

fn process_interrupt(context: &PacketContext) -> Option<String> {
    match context.status {
        Status::Ok => None,
        Status::BufferFull(val) => match (context.source_register_value & 0x1) == 1 {
            true => Some(format!("ACK_PRIMARY: Buffer Full detected with value {}", val)),
            false => Some("WARN_PRIMARY: Buffer full flag set but primary bit clear.".to_string()),
        },
        Status::FifoOverflow(is_active) => match (context.source_register_value & 0x2) == 2 {
            true if is_active => Some("ACK_FIFO: FIFO Overflow confirmed and active.".to_string()),
            true => Some("WARN_FIFO: FIFO bit set but overflow flag inactive.".to_string()),
            false => None,
        },
        Status::UnknownError(err) => Some(format!("FATAL_ERROR: Unknown hardware fault code {}", err)),
    }
}

fn main() {
    let context1 = PacketContext { status: Status::BufferFull(0xDEADBEEF), source_register_value: 1 };
    println!("{:?}", process_interrupt(&context1).unwrap_or_default());

    let context2 = PacketContext { status: Status::FifoOverflow(true), source_register_value: 2 };
    println!("{:?}", process_interrupt(&context2).unwrap_or_default());

    let context3 = PacketContext { status: Status::Ok, source_register_value: 0 };
    println!("Result for Ok state: {:?}", process_interrupt(&context3));
}

enum Particle { Small(f32), Large(String) } 
enum Effect { Fire(Particle), Water(u64), Dust { intensity: f32 } } 

fn render_effect(effect: Effect) -> String {
    match effect {
        Effect::Fire(Particle::Small(size)) => format!("Rendering small fire particle of size {}", size),
        Effect::Fire(Particle::Large(tag)) => format!("Rendering large, tagged fire particle: {}", tag),
        Effect::Water(timestamp) => format!("Rendering water effect recorded at timestamp {}", timestamp),
        Effect::Dust { intensity } => format!("Rendering dust cloud with intensity {:.2}", intensity),
    }
}

