use std::fmt;

#[derive(Debug)]
enum DeviceState {
    Idle,
    Configuring { step: u8 },
    ActiveReadback { cycles: u32 },
    ErrorShutdown(u16),
}

impl fmt::Display for DeviceState {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            DeviceState::Idle => write!(f, "STATE_IDLE"),
            DeviceState::Configuring { step } => write!(f, "CONFIGURING_STEP_{}", step),
            DeviceState::ActiveReadback { cycles } => write!(f, "READBACK_CYCLES_{}", cycles),
            DeviceState::ErrorShutdown(code) => write!(f, "ERROR_CODE_{:X}", code),
        }
    }
}

struct Processor {
    current_state: DeviceState,
}

impl Processor {
    fn new() -> Self {
        Processor { current_state: DeviceState::Idle }
    }

    fn process_cycle(&mut self) -> Result<(), &'static str> {
        match &self.current_state {
            DeviceState::Idle => {
                println!("Executing basic polling sequence.");
                self.current_state = DeviceState::Configuring { step: 1 };
                Ok(())
            }
            DeviceState::Configuring { step } => {
                if *step < 3 {
                    println!("Setting GPIO line {}", *step + 1);
                    self.current_state = DeviceState::Configuring { step: step + 1 };
                    Ok(())
                } else {
                    println!("Configuration complete, entering readback.");
                    self.current_state = DeviceState::ActiveReadback { cycles: 100 };
                    Ok(())
                }
            }
            DeviceState::ActiveReadback { cycles } => {
                if *cycles > 0 {
                    println!("Reading back data, remaining cycles: {}", cycles - 1);
                    self.current_state = DeviceState::ActiveReadback { cycles: cycles - 1 };
                    Ok(()) 
                } else {
                    println!("Readback finished successfully.");
                    self.current_state = DeviceState::Idle;
                    Ok(()) 
                }
            }
            DeviceState::ErrorShutdown(code) => {
                println!("Fatal error detected, halting system at code {}", code);
                Err("System Halted")
            }
        }
    }
}

fn main() {
    let mut processor = Processor::new();
    println!("Initial State: {}", processor.current_state);

    for i in 1..=5 {
        match processor.process_cycle() {
            Ok(_) => println!("Cycle {} finished. New State: {}", i, processor.current_state),
            Err(e) => { 
                println!("Error on cycle {}: {}", i, e);
                break;
            }
        }
    }
}

enum GameEvent {
    PlayerAction(String, String),
    SystemBroadcast(u32),
}

struct UnitState {
    is_enemy: bool,
    direction: String,
    target_id: String,
}

fn process_event(event: GameEvent) -> Option<String> {
    match event {
        GameEvent::PlayerAction(dir, target) => {
            if let Some(state) = load_unit_state(&target) {
                if state.is_enemy && dir == "North" && state.target_id == target {
                    Some(format!("Successfully processed hostile action from direction {}", dir))
                } else {
                    None
                }
            } else {
                None
            }
        },
        GameEvent::SystemBroadcast(_) => {
            println!("Ignoring system broadcast.");
            None
        }
    }
}

fn load_unit_state(target: &str) -> Option<UnitState> {
    if target == "Goblin" {
        Some(UnitState {
            is_enemy: true,
            direction: String::from("West"),
            target_id: String::from("EnemyTarget123")
        })
    } else if target == "NPCFriend" {
        Some(UnitState {
            is_enemy: false,
            direction: String::from("East"),
            target_id: String::from("SafeZone")
        })
    } else {
        None
    }
}

fn main() {
    let event1 = GameEvent::PlayerAction(String::from("North"), String::from("Goblin"));
    match process_event(event1) {
        Some(msg) => println!("Result 1: {}", msg),
        None => println!("Result 1: No action taken.")
    }

    let event2 = GameEvent::PlayerAction(String::from("South"), String::from("Goblin"));
    match process_event(event2) {
        Some(msg) => println!("Result 2: {}", msg),
        None => println!("Result 2: No action taken.")
    }
}

use std::collections::HashMap;

#[derive(Debug)]
pub enum ModelOutput {
    Embedding(f32),
    Metadata(String),
    Error(String),
}

#[derive(Debug)]
pub enum FeatureConfig {
    Simple(ModelOutput),
    Composite { 
        primary: Box<FeatureConfig>,
        secondary: Box<FeatureConfig>
    },
    Disabled
}

fn process_feature(config: &FeatureConfig) -> Result<f32, String> {
    match config {
        FeatureConfig::Simple(ModelOutput::Embedding(val)) => Ok(*val),
        FeatureConfig::Simple(ModelOutput::Metadata(_)) => Err("Cannot extract float from metadata".to_string()),
        FeatureConfig::Simple(ModelOutput::Error(e)) => Err(format!("Simple failure: {}", e)),
        FeatureConfig::Composite { primary, secondary } => {
            match (process_feature(primary), process_feature(secondary)) {
                (Ok(p_val), Ok(s_val)) => Ok((p_val + s_val) * 2.0),
                (Err(e1), _) => Err(format!("Failed on primary feature: {}", e1)),
                (_, Err(e2)) => Err(format!("Failed on secondary feature: {}", e2)),
            }
        },
        FeatureConfig::Disabled => Err("Feature is disabled".to_string()),
    }
}

fn main() {
    let nested_config = FeatureConfig::Composite {
        primary: Box::new(FeatureConfig::Simple(ModelOutput::Embedding(10.5))), 
        secondary: Box::new(FeatureConfig::Composite {
            primary: Box::new(FeatureConfig::Simple(ModelOutput::Metadata("User ID".to_string()))),
            secondary: Box::new(FeatureConfig::Simple(ModelOutput::Error("Missing required field".to_string()))) 
        })
    };

    match process_feature(&nested_config) {
        Ok(result) => println!("Successfully processed embedding value: {}", result),
        Err(e) => println!("Processing failed with error: {}", e),
    }
}
